import{_ as e,o as t,c,a as o}from"./app.9aed3a15.js";var p="/img/posts/git/1.png",i="/img/posts/git/2.png",d="/img/posts/git/3.png",a="/img/posts/git/4.png",r="/img/posts/git/5.png",g="/img/posts/git/6.png",n="/img/posts/git/7.png",s="/img/posts/git/8.png";const h={},m=o('<hr><p>\u5728\u5B66\u751F\u5B66\u4E1A\u53D1\u5C55\u4E0E\u8BC4\u4EF7\u7CFB\u7EDF\u4E2D\uFF0C\u5BF9\u4E8E\u4E94\u4EBA\u534F\u4F5C\u5F00\u53D1\u7684\u4E00\u4E9B\u6307\u5BFC</p><hr><h2 id="\u57FA\u672C\u64CD\u4F5C" tabindex="-1"><a class="header-anchor" href="#\u57FA\u672C\u64CD\u4F5C" aria-hidden="true">#</a> \u57FA\u672C\u64CD\u4F5C</h2><p>\u62C9\u53D6\u9879\u76EE\u5230\u672C\u5730 <code>git clone git@github.com:lxycxy/student-develop-sys.git</code></p><p>\u63D0\u4EA4\u4FEE\u6539\u5230\u6682\u5B58\u533A <code>git add .``.</code> \u4E3A\u9488\u5BF9\u6240\u6709\u4FEE\u6539\u7684\u6587\u4EF6\uFF0C\u4E5F\u53EF\u4EE5\u4F7F\u7528<code>\u6587\u4EF6\u540D</code>\u4EE3\u66FF <code>.</code></p><p>\u6682\u5B58\u533A\u63D0\u4EA4\u5230\u7248\u672C\u5E93 <code>git commit -m &quot;\u5907\u6CE8\u4FE1\u606F&quot;</code> \u6700\u597D\u662F\u7B80\u8981\u63CF\u8FF0\u4E00\u4E0B\u5B8C\u6210\u7684\u529F\u80FD</p><p>\u63D0\u4EA4\u4EE3\u7801 <code>git push</code></p><h2 id="\u56E2\u961F\u534F\u4F5C" tabindex="-1"><a class="header-anchor" href="#\u56E2\u961F\u534F\u4F5C" aria-hidden="true">#</a> \u56E2\u961F\u534F\u4F5C</h2><hr><p><em><strong>\u5199\u5728\u524D\u9762</strong></em></p><p>\u6B64\u5904\u6559\u7A0B\u53EA\u6709\u7B80\u5355dev\u5206\u652F\u64CD\u4F5C\uFF0C\u4F46\u4E2A\u4EBA\u5206\u652F\u7684\u5F00\u53D1\u4E5F\u9700\u8981\u51C6\u4ECE\u4E00\u5B9A\u7684\u89C4\u8303\uFF0C\u4E0B\u9762\u7684\u94FE\u63A5\u53EF\u4F5C\u53C2\u8003</p><p><a href="https://juejin.cn/post/6969090738961432613" target="_blank" rel="noopener noreferrer">git \u56E2\u961F\u5F00\u53D1\u89C4\u8303</a></p><hr><ol><li><p>\u521B\u5EFA\u4E2A\u4EBA\u5F00\u53D1\u5206\u652F\uFF0C\u540D\u5B57\u683C\u5F0F\u5982\u56FE\uFF0C\u59D3\u540D\u9996\u5B57\u6BCD\u52A0dev</p><p><img src="'+p+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p><p>\u521B\u5EFA\u6210\u529F</p><p><img src="'+i+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p></li><li><p>\u672C\u5730\u5207\u6362\u6216\u62C9\u53D6\u65B0\u5206\u652F</p><p><strong>\u5982\u679C\u5728\u521B\u5EFA\u5206\u652F\u524D\u5DF2\u7ECF\u62C9\u53D6\u4E86\u9879\u76EE\uFF0C\u5219\u5148<code>git pull</code>\uFF1B\u53CD\u6B63\u5219\u76F4\u63A5\u62C9\u53D6\u9879\u76EE</strong></p><p><code>git clone git@github.com:lxycxy/student-develop-sys.git</code></p><p><img src="'+d+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p><p>\u5207\u6362\u5206\u652F <code>git checkout &lt;\u5206\u652F\u540D&gt;</code></p><p><img src="'+a+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p></li><li><p>\u63D0\u4EA4\u4EE3\u7801(<strong>\u6CE8\u610F\u4E00\u5B9A\u662F\u5728\u81EA\u5DF1\u7684\u5206\u652F</strong>)</p><p>\u5B8C\u6210\u81EA\u5DF1\u7684\u529F\u80FD\u5F00\u53D1\u540E\u5373\u53EF\u63D0\u4EA4</p><p><img src="'+r+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p><p>\u53D1\u8D77\u5408\u5E76\u8BF7\u6C42</p><p><img src="'+g+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p><p><img src="'+n+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p><p>\u5408\u5E76\u5230master\u5206\u652F\u6210\u529F</p><p><img src="'+s+'" alt="\u56FE\u7247" title="\u56FE\u7247"></p></li></ol><h2 id="git" tabindex="-1"><a class="header-anchor" href="#git" aria-hidden="true">#</a> Git</h2><h3 id="git\u57FA\u672C\u6982\u5FF5" tabindex="-1"><a class="header-anchor" href="#git\u57FA\u672C\u6982\u5FF5" aria-hidden="true">#</a> git\u57FA\u672C\u6982\u5FF5</h3><p>\u5DE5\u4F5C\u533A\uFF1A\u4ED3\u5E93\u7684\u76EE\u5F55\u3002\u5DE5\u4F5C\u533A\u662F\u72EC\u7ACB\u4E8E\u5404\u4E2A\u5206\u652F\u7684\u3002</p><p>\u6682\u5B58\u533A\uFF1A\u6570\u636E\u6682\u65F6\u5B58\u653E\u7684\u533A\u57DF\uFF0C\u7C7B\u4F3C\u4E8E\u5DE5\u4F5C\u533A\u5199\u5165\u7248\u672C\u5E93\u524D\u7684\u7F13\u5B58 \u533A\u3002\u6682\u5B58\u533A\u662F\u72EC\u7ACB\u4E8E\u5404\u4E2A\u5206\u652F\u7684\u3002</p><p>\u7248\u672C\u5E93\uFF1A\u5B58\u653E\u6240\u6709\u5DF2\u7ECF\u63D0\u4EA4\u5230\u672C\u5730\u4ED3\u5E93\u7684\u4EE3\u7801\u7248\u672C</p><p>\u7248\u672C\u7ED3\u6784\uFF1A\u6811\u7ED3\u6784\uFF0C\u6811\u4E2D\u6BCF\u4E2A\u8282\u70B9\u4EE3\u8868\u4E00\u4E2A\u4EE3\u7801\u7248\u672C\u3002</p><h3 id="git\u5E38\u7528\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#git\u5E38\u7528\u547D\u4EE4" aria-hidden="true">#</a> git\u5E38\u7528\u547D\u4EE4</h3><p><code>git config --global user.name xxx</code>\uFF1A\u8BBE\u7F6E\u5168\u5C40\u7528\u6237\u540D\uFF0C\u4FE1\u606F\u8BB0\u5F55\u5728~/.gitconfig\u6587\u4EF6\u4E2D</p><p><code>git config --global user.email xxx@xxx.com</code>\uFF1A\u8BBE\u7F6E\u5168\u5C40\u90AE\u7BB1\u5730\u5740\uFF0C\u4FE1\u606F\u8BB0\u5F55\u5728~/.gitconfig\u6587\u4EF6\u4E2D</p><p><code>git init</code>\uFF1A\u5C06\u5F53\u524D\u76EE\u5F55\u914D\u7F6E\u6210git\u4ED3\u5E93\uFF0C\u4FE1\u606F\u8BB0\u5F55\u5728\u9690\u85CF\u7684.git\u6587\u4EF6\u5939\u4E2D</p><p><code>git add XX</code>\uFF1A\u5C06XX\u6587\u4EF6\u6DFB\u52A0\u5230\u6682\u5B58\u533A</p><p><code>git add .</code>\uFF1A\u5C06\u6240\u6709\u5F85\u52A0\u5165\u6682\u5B58\u533A\u7684\u6587\u4EF6\u52A0\u5165\u6682\u5B58\u533A</p><p><code>git rm --cached XX</code>\uFF1A\u5C06\u6587\u4EF6\u4ECE\u4ED3\u5E93\u7D22\u5F15\u76EE\u5F55\u4E2D\u5220\u6389</p><p><code>git commit -m &quot;\u7ED9\u81EA\u5DF1\u770B\u7684\u5907\u6CE8\u4FE1\u606F&quot;</code>\uFF1A\u5C06\u6682\u5B58\u533A\u7684\u5185\u5BB9\u63D0\u4EA4\u5230\u5F53\u524D\u5206\u652F</p><p><code>git status</code>\uFF1A\u67E5\u770B\u4ED3\u5E93\u72B6\u6001</p><p><code>git diff XX</code>\uFF1A\u67E5\u770BXX\u6587\u4EF6\u76F8\u5BF9\u4E8E\u6682\u5B58\u533A\u4FEE\u6539\u4E86\u54EA\u4E9B\u5185\u5BB9</p><p><code>git log</code>\uFF1A\u67E5\u770B\u5F53\u524D\u5206\u652F\u7684\u6240\u6709\u7248\u672C</p><p><code>git reflog</code>\uFF1A\u67E5\u770BHEAD\u6307\u9488\u7684\u79FB\u52A8\u5386\u53F2\uFF08\u5305\u62EC\u88AB\u56DE\u6EDA\u7684\u7248\u672C\uFF09</p><p><code>git reset --hard HEAD^</code> \u6216 <code>git reset --hard HEAD~</code>\uFF1A\u5C06\u4EE3\u7801\u5E93\u56DE\u6EDA\u5230\u4E0A\u4E00\u4E2A\u7248\u672C</p><p><code>git reset --hard HEAD^^</code>\uFF1A\u5F80\u4E0A\u56DE\u6EDA\u4E24\u6B21\uFF0C\u4EE5\u6B64\u7C7B\u63A8</p><p><code>git reset --hard HEAD~100</code>\uFF1A\u5F80\u4E0A\u56DE\u6EDA100\u4E2A\u7248\u672C</p><p><code>git reset --hard \u7248\u672C\u53F7</code>\uFF1A\u56DE\u6EDA\u5230\u67D0\u4E00\u7279\u5B9A\u7248\u672C</p><p><code>git checkout \u2014 XX\u6216git restore XX</code>\uFF1A\u5C06XX\u6587\u4EF6\u5C1A\u672A\u52A0\u5165\u6682\u5B58\u533A\u7684\u4FEE\u6539\u5168\u90E8\u64A4\u9500</p><p><code>git remote add origin git@git.acwing.com:xxx/XXX.git</code>\uFF1A\u5C06\u672C\u5730\u4ED3\u5E93\u5173\u8054\u5230\u8FDC\u7A0B\u4ED3\u5E93</p><p><code>git push -u (\u7B2C\u4E00\u6B21\u9700\u8981-u\u4EE5\u540E\u4E0D\u9700\u8981)</code>\uFF1A\u5C06\u5F53\u524D\u5206\u652F\u63A8\u9001\u5230\u8FDC\u7A0B\u4ED3\u5E93</p><p><code>git push origin branch_name</code>\uFF1A\u5C06\u672C\u5730\u7684\u67D0\u4E2A\u5206\u652F\u63A8\u9001\u5230\u8FDC\u7A0B\u4ED3\u5E93</p><p><code>git clone git@git.acwing.com:xxx/XXX.git</code>\uFF1A\u5C06\u8FDC\u7A0B\u4ED3\u5E93XXX\u4E0B\u8F7D\u5230\u5F53\u524D\u76EE\u5F55\u4E0B</p><p><code>git checkout -b branch_name</code>\uFF1A\u521B\u5EFA\u5E76\u5207\u6362\u5230branch_name\u8FD9\u4E2A\u5206\u652F</p><p><code>git branch</code>\uFF1A\u67E5\u770B\u6240\u6709\u5206\u652F\u548C\u5F53\u524D\u6240\u5904\u5206\u652F</p><p><code>git checkout branch_name</code>\uFF1A\u5207\u6362\u5230branch_name\u8FD9\u4E2A\u5206\u652F</p><p><code>git merge branch_name</code>\uFF1A\u5C06\u5206\u652Fbranch_name\u5408\u5E76\u5230\u5F53\u524D\u5206\u652F\u4E0A</p><p><code>git branch -d branch_name</code>\uFF1A\u5220\u9664\u672C\u5730\u4ED3\u5E93\u7684branch_name\u5206\u652F</p><p><code>git branch branch_name</code>\uFF1A\u521B\u5EFA\u65B0\u5206\u652F</p><p><code>git push --set-upstream origin branch_name</code>\uFF1A\u8BBE\u7F6E\u672C\u5730\u7684branch_name\u5206\u652F\u5BF9\u5E94\u8FDC\u7A0B\u4ED3\u5E93\u7684branch_name\u5206\u652F</p><p><code>git push -d origin branch_name</code>\uFF1A\u5220\u9664\u8FDC\u7A0B\u4ED3\u5E93\u7684branch_name\u5206\u652F</p><p><code>git pull</code>\uFF1A\u5C06\u8FDC\u7A0B\u4ED3\u5E93\u7684\u5F53\u524D\u5206\u652F\u4E0E\u672C\u5730\u4ED3\u5E93\u7684\u5F53\u524D\u5206\u652F\u5408\u5E76</p><p><code>git pull origin branch_name</code>\uFF1A\u5C06\u8FDC\u7A0B\u4ED3\u5E93\u7684branch_name\u5206\u652F\u4E0E\u672C\u5730\u4ED3\u5E93\u7684\u5F53\u524D\u5206\u652F\u5408\u5E76</p><p><code>git branch --set-upstream-to=origin/branch_name1 branch_name2</code>\uFF1A\u5C06\u8FDC\u7A0B\u7684branch_name1\u5206\u652F\u4E0E\u672C\u5730\u7684branch_name2\u5206\u652F\u5BF9\u5E94</p><p><code>git checkout -t origin/branch_name</code> \u5C06\u8FDC\u7A0B\u7684branch_name\u5206\u652F\u62C9\u53D6\u5230\u672C\u5730</p><p><code>git stash</code>\uFF1A\u5C06\u5DE5\u4F5C\u533A\u548C\u6682\u5B58\u533A\u4E2D\u5C1A\u672A\u63D0\u4EA4\u7684\u4FEE\u6539\u5B58\u5165\u6808\u4E2D</p><p><code>git stash apply</code>\uFF1A\u5C06\u6808\u9876\u5B58\u50A8\u7684\u4FEE\u6539\u6062\u590D\u5230\u5F53\u524D\u5206\u652F\uFF0C\u4F46\u4E0D\u5220\u9664\u6808\u9876\u5143\u7D20</p><p><code>git stash drop</code>\uFF1A\u5220\u9664\u6808\u9876\u5B58\u50A8\u7684\u4FEE\u6539</p><p><code>git stash pop</code>\uFF1A\u5C06\u6808\u9876\u5B58\u50A8\u7684\u4FEE\u6539\u6062\u590D\u5230\u5F53\u524D\u5206\u652F\uFF0C\u540C\u65F6\u5220\u9664\u6808\u9876\u5143\u7D20</p><p><code>git stash list</code>\uFF1A\u67E5\u770B\u6808\u4E2D\u6240\u6709\u5143\u7D20</p><h2 id="\u51B2\u7A81\u89E3\u51B3" tabindex="-1"><a class="header-anchor" href="#\u51B2\u7A81\u89E3\u51B3" aria-hidden="true">#</a> \u51B2\u7A81\u89E3\u51B3</h2><p><code>git stash</code> \u4FDD\u5B58\u8D2E\u85CF</p><p><code>git pull</code> \u62C9\u53D6</p><p><code>git stash pop</code> \u5F39\u51FA\u8D2E\u85CF \uFF08\u6B64\u65F6\u4F1A\u5C06\u66F4\u65B0\u7684\u4EE3\u7801\u548C\u81EA\u5DF1\u5199\u7684\u4EE3\u7801\u5408\u5E76\uFF0C\u53EF\u80FD\u4F1A\u6709\u51B2\u7A81\uFF0C\u9700\u8981\u624B\u52A8\u89E3\u51B3\u51B2\u7A81\uFF09</p>',63),l=[m];function _(u,b){return t(),c("div",null,l)}var X=e(h,[["render",_],["__file","GitInstruction.html.vue"]]);export{X as default};
